import{_ as t,c as e,o as r,a as n}from"./app.75fe7403.js";const a="/assets/ibm-sj-ad-1962.7c3c0d22.jpg",x=JSON.parse('{"title":"QueryFirst - Frictionless Data Access","description":"","frontmatter":{},"headers":[{"level":3,"title":"Author your SQL in a real environment","slug":"author-your-sql-in-a-real-environment","link":"#author-your-sql-in-a-real-environment","children":[]},{"level":3,"title":"A generated C# wrapper","slug":"a-generated-c-wrapper","link":"#a-generated-c-wrapper","children":[]},{"level":3,"title":"TL;dr","slug":"tl-dr","link":"#tl-dr","children":[]},{"level":3,"title":"Ambitious?","slug":"ambitious","link":"#ambitious","children":[]}],"relativePath":"index.md"}'),i={name:"index.md"},l=n('<p><img src="'+a+'" alt="An image"></p><h1 id="queryfirst-frictionless-data-access" tabindex="-1">QueryFirst - Frictionless Data Access <a class="header-anchor" href="#queryfirst-frictionless-data-access" aria-hidden="true">#</a></h1><p>QueryFirst generates a C# wrapper for your .sql files. Install it as an extension in <strong><a href="https://marketplace.visualstudio.com/items?itemName=bbsimonbb.QueryFirstVS17" target="_blank" rel="noreferrer">Visual Studio 2022</a></strong>, or <a href="https://marketplace.visualstudio.com/items?itemName=bbsimonbb.QueryFirst" target="_blank" rel="noreferrer">Visual Studio 2019</a>, or you can use it directly from the command line. (See installation)</p><h3 id="author-your-sql-in-a-real-environment" tabindex="-1">Author your SQL in a real environment <a class="header-anchor" href="#author-your-sql-in-a-real-environment" aria-hidden="true">#</a></h3><p>Syntax checking- Intellisense for tables and columns - Get familiar with your data</p><h3 id="a-generated-c-wrapper" tabindex="-1">A generated C# wrapper <a class="header-anchor" href="#a-generated-c-wrapper" aria-hidden="true">#</a></h3><ul><li><p>Repo, POCO, Interface.</p></li><li><p>Repository pattern - Parameter discovery - Type safety - POCOs generated from your result schema</p></li><li><p>Supports Sql Server, Postgres and MySql</p></li><li><p>Supports all C# project types including .net core.</p></li></ul><p><strong>To use QueryFirst, install the extension, then use the QueryFirst .sql template under Add =&gt; New item =&gt; Visual C# Items</strong></p><h3 id="tl-dr" tabindex="-1">TL;dr <a class="header-anchor" href="#tl-dr" aria-hidden="true">#</a></h3><p>Query-first is a visual studio extension for working intelligently with SQL in C# projects. Use the provided .sql template to develop your queries. When you save the file, Query-first runs your query, retrieves the schema and generates two classes and an interface: a wrapper class with methods Execute(), ExecuteScalar(), ExecuteNonQuery() etc, its corresponding interface, and a POCO encapsulating a line of results.</p><p><strong>As such, your query stays intact</strong> in its own .sql file. It can be edited, validated and test-run &quot;in-situ&quot; with design-time mock inputs and intellisense for your tables and columns. In your application code, running your query takes one line of code, and returns a POCO (or an IEnumerable of POCOs, or a List of POCOs) with meaningful parameter and property names, so <em>enabling intellisense for your input parameters and results</em>. The interface and POCO are directly usable for unit testing.</p><p>The generated code stands alone. There is no runtime dll and no reflection. The only dependencies are System libraries. You can quietly forget about ADO : Command, Connection, Reader and parameter creation are all handled for you, with best practices baked in. At no point do you have to remember the name of a column, or its type, or its index in the reader. And you&#39;ve absolutely nothing new \xA0to learn, provided you still remember how to write SQL \u{1F603}</p><p>QueryFirst puts a command in your Tools menu that will run all queries in your application and regenerate all wrapper classes. As such, you can integration-test all your queries at any time, and changes in your database schema will directly produce compilation errors in your application. If the query is broken, the wrapper classes will not compile. If the query runs but your code tries to access columns that are no longer present in the result, the error will point at <em>the line in your code</em> that tries to access the missing property.</p><p>QueryFirst, first published in 2016, represents an original approach to the database problem <em>in any language</em>. Your comments are very welcome.</p><h3 id="ambitious" tabindex="-1">Ambitious? <a class="header-anchor" href="#ambitious" aria-hidden="true">#</a></h3><p>We expect that QueryFirst will quickly become your favourite data access method. Please urgently let us know if this is not the case.</p><table><thead><tr><th style="text-align:left;"></th><th style="text-align:center;">Dapper</th><th style="text-align:center;">EF</th><th style="text-align:center;">Stored procs</th><th style="text-align:center;">QueryFirst</th></tr></thead><tbody><tr><td style="text-align:left;">Lightweight, low ceremony</td><td style="text-align:center;">x</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Does whatever SQL can do</td><td style="text-align:center;">x</td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Interact with your data as you develop projections</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Type safety/compile-time checking of your projection</td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;">meh</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">No POCOs to maintain</td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;">x*</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Provides an interface to facilitate testing the calling code</td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;">x*</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Prevents SQL injection</td><td style="text-align:center;">**</td><td style="text-align:center;">x</td><td style="text-align:center;">x</td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Queries distributed and versioned with application code</td><td style="text-align:center;">x</td><td style="text-align:center;">x</td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Bundles an integration test to verify your production schema</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Typesafe dynamic ORDER BY</td><td style="text-align:center;"></td><td style="text-align:center;">x</td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Expando params (EF Contains)</td><td style="text-align:center;">x</td><td style="text-align:center;">x</td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Scaffolded INSERTS and UPDATES</td><td style="text-align:center;"></td><td style="text-align:center;">na</td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr><tr><td style="text-align:left;">Generated Typescript interfaces from your projections</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">x</td></tr></tbody></table><p>* only with the help of EF reverse POCO generator (not actually part of EF), but you&#39;ll need to open your solution <em>as administrator</em>, find the .tt and right-click on &#39;run custom tool&#39;. Not kidding.</p><p>** Dapper makes parameters much easier, so you&#39;re encouraged, but not obliged, to use them.</p>',19),s=[l];function d(o,c,u,y,p,g){return r(),e("div",null,s)}const m=t(i,[["render",d]]);export{x as __pageData,m as default};
